#include <bits/stdc++.h>
using namespace std;

int w, h;
int g[55][55];
bool vis[55][55];
int dx[8] = {-1,-1,-1,0,0,1,1,1};
int dy[8] = {-1,0,1,-1,1,-1,0,1};

void bfs(int sy, int sx) {
    queue<pair<int,int>> q;
    q.push({sy, sx});
    vis[sy][sx] = true;
    while (!q.empty()) {
        auto [y, x] = q.front(); q.pop();
        for (int d = 0; d < 8; d++) {
            int ny = y + dy[d], nx = x + dx[d];
            if (ny < 0 || ny >= h || nx < 0 || nx >= w) continue;
            if (vis[ny][nx] || g[ny][nx] == 0) continue;
            vis[ny][nx] = true;
            q.push({ny, nx});
        }
    }
}

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    cin >> w >> h;
    for (int i = 0; i < h; i++)
        for (int j = 0; j < w; j++)
            cin >> g[i][j];
    int cnt = 0;
    for (int i = 0; i < h; i++)
        for (int j = 0; j < w; j++)
            if (g[i][j] == 1 && !vis[i][j]) { bfs(i, j); cnt++; }
    cout << cnt << "\n";
    return 0;
}
